#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int n;
        scanf("%d", &n);
        int V[n];

        for (int i = 0; i < n; i++) {
            scanf("%d", &V[i]);
        }

        // Sort in descending order
        qsort(V, n, sizeof(int), cmp_desc);

        int max1 = 0, max2 = 0;
        int i = 0;

        // Find the first pair of equal sticks
        while (i < n - 1) {
            if (V[i] == V[i + 1]) {
                max1 = V[i];
                i += 2;
                break;
            }
            i++;
        }

        // Find the second pair of equal sticks
        while (i < n - 1) {
            if (V[i] == V[i + 1]) {
                max2 = V[i];
                i += 2;
                break;
            }
            i++;
        }

        if (max1 > 0 && max2 > 0) {
            printf("%d\n", max1 * max2);
        } else {
            printf("-1\n");
        }
    }

    return 0;
}

